`,t.jsxs(n.li,{children:[t.jsx(n.strong,{children:"Catastrophic:"})," workflow infrastructure failure or unrecoverable release failure. Emit alarms and rely on defense-in-depth cleanup."]}),`
`]}),`
`,t.jsxs(n.p,{children:["The invariant is simple: ",t.jsx(n.strong,{children:"any test data acquired for a marketplace must be released before that marketplace iteration terminates."})]}),`
`,t.jsxs(n.p,{children:["Within each Map iteration, failures after acquisition route through ",t.jsx(n.code,{children:"ReleaseTestDataCompensation"}),". That Lambda queries DynamoDB for locks owned by this ",t.jsx(n.code,{children:"testRunId"}),", ",t.jsx(n.code,{children:"testSuiteId"}),", and ",t.jsx(n.code,{children:"marketplace"}),", then releases only those locks. Other marketplace iterations continue unaffected."]}),`
`,t.jsx(n.p,{children:"There is also a stale-lock cleanup Lambda outside the workflow, triggered by EventBridge. If a workflow is cancelled or compensation itself fails, the cleanup path releases expired locks without deleting the underlying test-data configuration. TTL was not appropriate because the data item must remain available. Only the lock fields should be removed."}),`
`,t.jsx(n.h2,{id:"the-results",children:t.jsx(n.a,{href:"#the-results",children:"The results"})}),`
`,t.jsx(n.p,{children:"The design produced a workflow with clear operational properties:"}),`
`,t.jsxs(n.ul,{children:[`
`,t.jsxs(n.li,{children:[t.jsx(n.strong,{children:"Marketplace-level isolation."})," A failure in one marketplace does not block results from others."]}),`
`,t.jsxs(n.li,{children:[t.jsx(n.strong,{children:"Precise compensation."})," Failed iterations release only the test data they own."]}),`
`,t.jsxs(n.li,{children:[t.jsx(n.strong,{children:"Long-running execution support."})," Test Executor callbacks allow up to seven-day runs without polling compute."]}),`
`,t.jsxs(n.li,{children:[t.jsx(n.strong,{children:"Result durability."})," Detailed test counts and reports are persisted in DynamoDB during execution; aggregation reads from storage rather than relying on callback payloads."]}),`
`,t.jsxs(n.li,{children:[t.jsx(n.strong,{children:"Observable state transitions."})," Every state emits structured logs and metrics for debugging and alerting."]}),`
`]}),`
`,t.jsx(n.p,{children:"The most important result is not that the workflow can run tests. It is that the workflow can fail without corrupting shared test data or losing unrelated marketplace results."}),`
`,t.jsx(n.h2,{id:"tradeoffs-and-limitations",children:t.jsx(n.a,{href:"#tradeoffs-and-limitations",children:"Tradeoffs and limitations"})}),`
`,t.jsxs(n.p,{children:[t.jsx(n.strong,{children:"Map state adds ASL complexity."})," A single bundled test run would have been simpler on paper. The Map design introduces more states and more per-iteration error handling. I accepted that complexity because it buys isolation, compensation precision, and marketplace-level observability."]}),`
`,t.jsxs(n.p,{children:[t.jsx(n.strong,{children:"Multiple test executions can increase orchestration overhead."})," The workflow may start one execution per test suite and marketplace. That is more orchestration than a single bundled run, but each execution is smaller and failures are scoped."]}),`
`,t.jsxs(n.p,{children:[t.jsx(n.strong,{children:"Callback has weak heartbeat semantics."})," If the Test Executor crashes early and never calls back, Step Functions waits until the configured timeout. Progress visibility lives in DynamoDB, not in the callback. That is acceptable, but it means the UI and alarms must read execution progress from storage."]}),`
`,t.jsxs(n.p,{children:[t.jsx(n.strong,{children:"Locking is deliberately simple."})," DynamoDB conditional writes are enough for the current concurrency profile. A dedicated locking service would add operational complexity without clear benefit."]}),`
`,t.jsx(n.h2,{id:"what-i-would-do-differently",children:t.jsx(n.a,{href:"#what-i-would-do-differently",children:"What I would do differently"})}),`
`,t.jsxs(n.p,{children:[t.jsx(n.strong,{children:"Design the stale-lock path at the same time as the happy path."})," It is tempting to add cleanup later, but in orchestration systems cleanup is part of correctness. The stale-lock Lambda should be treated as a first-class component from day one."]}),`
`,t.jsxs(n.p,{children:[t.jsx(n.strong,{children:"Make compensation visible in the UI."})," Operators should be able to see that a failed marketplace released its test data cleanly. That turns a scary failure into a known terminal state."]}),`
`,t.jsxs(n.p,{children:[t.jsx(n.strong,{children:"Write failure-category docs before ASL."})," Once failure modes are categorized as transient, deterministic, or catastrophic, the state machine becomes easier to reason about."]}),`
`,t.jsx(n.h2,{id:"what-this-work-taught-me",children:t.jsx(n.a,{href:"#what-this-work-taught-me",children:"What this work taught me"})}),`
`,t.jsx(n.p,{children:"Good orchestration is mostly about bounded failure. The happy path is usually straightforward. The design quality shows up when only one marketplace fails, when a callback never arrives, when test data is scarce, or when cleanup has to run after partial progress."}),`
`,t.jsx(n.p,{children:"Step Functions gave us the right primitives: Map state for isolation, callback tokens for long-running execution, retries for transient failures, and explicit compensation paths for cleanup. The engineering work was deciding where to spend that complexity so the workflow remained debuggable."})]})}function qw(a={}){const{wrapper:n}={...Y(),...a.components};return n?t.jsx(n,{...a,children:t.jsx(Au,{...a})}):Au(a)}const Bw=Object.freeze(Object.defineProperty({__proto__:null,default:qw,frontmatter:zw},Symbol.toStringTag,{value:"Module"})),Uw={title:"EU DSA compliance pipeline",slug:"eu-dsa-pipeline",eyebrow:"Amazon · Regulatory Data",description:"A PySpark pipeline processing 30M+ monthly records for EU Digital Services Act transparency reporting, built around schema versioning, replayable error isolation, and audit-grade traceability.",date:"2026-05-15",tech:["PySpark","AWS Glue","Python","Distributed Systems"],stat:{number:"70% ↓",label:"Incident resolution time"},diagram:{nodes:["ingest","validate","transform","aggregate","submit"],caption:"isolate errors, preserve audit state"},featured:!1,order:5};function Ru(a){const n={a:"a",blockquote:"blockquote",code:"code",h2:"h2",h3:"h3",li:"li",ol:"ol",p:"p",pre:"pre",strong:"strong",ul:"ul",...Y(),...a.components};return t.jsxs(t.Fragment,{children:[t.jsxs(n.blockquote,{children:[`
